from gmpy2 import gcd, invert, iroot
from libnum import n2s

n1 = int('', 5)
c1 = int('', 5)
n2 = int('', 5)
c2 = int('', 5)
n3 = int('', 5)
c3 = int('', 5)
n_list = [n1, n2, n3]
c_list = [c1, c2, c3]

# 看是不是两两互质
for i in range(len(n_list)):
    for j in range(i + 1, len(n_list)):
        g = gcd(n_list[i], n_list[j])
        print(i, j, g)

N = n1 * n2 * n3
m_e = 0
for i in range(len(n_list)):
    N_i = N // n_list[i]
    m_e = (m_e + c_list[i] * N_i * invert(N_i, n_list[i])) % N
print(m_e)
# n1 = 
# m_e= 
# 所以猜测 e 比较小，尝试 e=3
ans = 114514
for k in range(100):
    m_e_actual = m_e + k * N
    wanted, ok = iroot(m_e_actual, 3)
    if not ok:
        continue
    ans = wanted
    print(k, ans)
    break
flag = n2s(int(ans)).decode('utf-8')
print(flag)
